import { describe, it, expect } from "vitest";
import type { ModelMessage } from "ai";
import type {
  Message,
  CheckpointMessage,
  SessionMetadata,
  CompactionConfig,
  PruningConfig,
  ContinuationVariant,
  CompactionResult,
  PreparedCompactionV2,
  ActualTokenUsage,
  ActualTokenUsageInput,
  ContextUsage,
  TodoItem,
  StructuredState,
  SessionHeaderLine,
  MessageLine,
  CheckpointLine,
  SessionFileLine,
  CompactionSummary,
  CompactionSegment,
  PreparedCompactionSegment,
  PreparedCompaction,
} from "./compaction-types";

// Helper to create ModelMessage
const createModelMessage = (
  content: string,
  role: "user" | "assistant" | "system" | "tool" = "user"
): ModelMessage => ({ role, content }) as ModelMessage;

describe("Message Interface", () => {
  it("should have required fields: createdAt, id, modelMessage", () => {
    const message: Message = {
      createdAt: new Date("2024-01-01"),
      id: "msg-001",
      modelMessage: createModelMessage("Hello world"),
    };
    expect(message.createdAt).toBeInstanceOf(Date);
