import { describe, it, expect, expectTypeOf } from "vitest";
import type { ModelMessage } from "ai";
import type {
  Message,
  CheckpointMessage,
  SessionMetadata,
  CompactionConfig,
  PruningConfig,
  ContinuationVariant,
  CompactionResult,
  PreparedCompactionV2,
  ActualTokenUsage,
  ActualTokenUsageInput,
  ContextUsage,
  TodoItem,
  StructuredState,
  SessionHeaderLine,
  MessageLine,
  CheckpointLine,
  SessionFileLine,
  CompactionSummary,
  CompactionSegment,
  PreparedCompactionSegment,
  PreparedCompaction,
} from "./compaction-types";

describe("compaction-types", () => {
  // ============================================
  // 1. Message Interface
  // ============================================
  describe("Message", () => {
    it("should have required fields: createdAt, id, modelMessage", () => {
      const message: Message = {
        createdAt: new Date(),
        id: "msg-123",
        modelMessage: { role: "user", content: "Hello" },
      };
      expect(message.createdAt).toBeInstanceOf(Date);
      expect(message.id).toBe("msg-123");
      expect(message.modelMessage).toBeDefined();
    });

    it("should allow optional originalContent field", () => {
      const message: Message = {
        createdAt: new Date(),
        id: "msg-123",
        modelMessage: { role: "user", content: "Hello" },
        originalContent: "original text",
      };
      expect(message.originalContent).toBe("original text");
    });

    it("should reject when required fields are missing", () => {
      // @ts-expect-error - missing required fields
      const invalidMessage: Message = {};
      expect(invalidMessage).toBeDefined();
    });

    it("should be compatible with type assignment", () => {
      const message: Message = {
        createdAt: new Date(),
        id: "msg-123",
        modelMessage: { role: "user", content: "Hello" },
      };
      const messageWithOriginal: Message = {
        ...message,
        originalContent: "test",
      };
      expect(messageWithOriginal.originalContent).toBe("test");
    });
  });

  // ============================================
  // 2. CheckpointMessage Interface
  // ============================================
  describe("CheckpointMessage", () => {
    it("should have required fields: createdAt, id, isSummary, message", () => {
      const checkpoint: CheckpointMessage = {
        createdAt: Date.now(),
        id: "cp-123",
        isSummary: false,
        message: { role: "assistant", content: "Response" },
      };
      expect(checkpoint.createdAt).toBeDefined();
      expect(checkpoint.id).toBe("cp-123");
      expect(checkpoint.isSummary).toBe(false);
      expect(checkpoint.message).toBeDefined();
    });

    it("should allow optional isSummaryMessage field", () => {
      const checkpoint: CheckpointMessage = {
        createdAt: Date.now(),
        id: "cp-123",
        isSummary: true,
        isSummaryMessage: true,
        message: { role: "assistant", content: "Summary" },
      };
      expect(checkpoint.isSummaryMessage).toBe(true);
    });

    it("should allow optional originalContent field", () => {
      const checkpoint: CheckpointMessage = {
        createdAt: Date.now(),
        id: "cp-123",
        isSummary: false,
        message: { role: "assistant", content: "Response" },
        originalContent: "original",
      };
      expect(checkpoint.originalContent).toBe("original");
    });

    it("should reject when required fields are missing", () => {
      // @ts-expect-error - missing required fields
      const invalid: CheckpointMessage = {};
      expect(invalid).toBeDefined();
    });
  });

  // ============================================
  // 3. SessionMetadata Interface
  // ============================================
  describe("SessionMetadata", () => {
    it("should have all required fields", () => {
      const metadata: SessionMetadata = {
        completionTokens: 100,
        createdAt: Date.now(),
        promptTokens: 50,
        sessionId: "session-123",
        summaryMessageId: null,
        updatedAt: Date.now(),
      };
      expect(metadata.completionTokens).toBe(100);
      expect(metadata.promptTokens).toBe(50);
      expect(metadata.sessionId).toBe("session-123");
      expect(metadata.summaryMessageId).toBeNull();
      expect(metadata.createdAt).toBeDefined();
      expect(metadata.updatedAt).toBeDefined();
    });

    it("should allow summaryMessageId to be a string", () => {
      const metadata: SessionMetadata = {
        completionTokens: 100,
        createdAt: Date.now(),
        promptTokens: 50,
        sessionId: "session-123",
        summaryMessageId: "summary-456",
        updatedAt: Date.now(),
      };
      expect(metadata.summaryMessageId).toBe("summary-456");
    });

    it("should reject when required fields are missing", () => {
      // @ts-expect-error - missing required fields
      const invalid: SessionMetadata = {};
      expect(invalid).toBeDefined();
    });
  });

  // ============================================
  // 4. CompactionConfig Interface
  // ============================================
  describe("CompactionConfig", () => {
    it("should have all optional fields with default values from JSDoc", () => {
      const config: CompactionConfig = {};
      // Default values from JSDoc comments:
      // contextLimit: 128000
      // enabled: false
      // keepRecentTokens: 2000
      // maxTokens: 8000
      // reserveTokens: 2000
      // speculativeStartRatio: 0.5
      // thresholdRatio: 0.5
      expect(config.contextLimit).toBeUndefined();
      expect(config.enabled).toBeUndefined();
      expect(config.keepRecentTokens).toBeUndefined();
      expect(config.maxTokens).toBeUndefined();
      expect(config.reserveTokens).toBeUndefined();
      expect(config.speculativeStartRatio).toBeUndefined();
      expect(config.thresholdRatio).toBeUndefined();
    });

    it("should allow setting contextLimit", () => {
      const config: CompactionConfig = { contextLimit: 128000 };
      expect(config.contextLimit).toBe(128000);
    });

    it("should allow setting enabled", () => {
      const config: CompactionConfig = { enabled: true };
      expect(config.enabled).toBe(true);
    });

    it("should allow setting keepRecentTokens", () => {
      const config: CompactionConfig = { keepRecentTokens: 2000 };
      expect(config.keepRecentTokens).toBe(2000);
    });

    it("should allow setting maxTokens", () => {
      const config: CompactionConfig = { maxTokens: 8000 };
      expect(config.maxTokens).toBe(8000);
    });

    it("should allow setting reserveTokens", () => {
      const config: CompactionConfig = { reserveTokens: 2000 };
      expect(config.reserveTokens).toBe(2000);
    });

    it("should allow setting speculativeStartRatio", () => {
      const config: CompactionConfig = { speculativeStartRatio: 0.5 };
      expect(config.speculativeStartRatio).toBe(0.5);
    });

    it("should allow setting thresholdRatio", () => {
      const config: CompactionConfig = { thresholdRatio: 0.5 };
      expect(config.thresholdRatio).toBe(0.5);
    });

    it("should allow setting getStructuredState callback", () => {
      const config: CompactionConfig = {
        getStructuredState: () => "state data",
      };
      expect(config.getStructuredState).toBeDefined();
      expect(config.getStructuredState!()).toBe("state data");
    });

    it("should allow setting summarizeFn callback", () => {
      const summarizeFn: CompactionConfig["summarizeFn"] = async (
        messages,
        previousSummary
      ) => {
        return "summary";
      };
      const config: CompactionConfig = { summarizeFn };
      expect(config.summarizeFn).toBeDefined();
    });

    it("should allow all fields to be set together", () => {
      const config: CompactionConfig = {
        contextLimit: 128000,
        enabled: true,
        getStructuredState: () => "state",
        keepRecentTokens: 2000,
        maxTokens: 8000,
        reserveTokens: 2000,
        speculativeStartRatio: 0.5,
        summarizeFn: async () => "summary",
        thresholdRatio: 0.5,
      };
      expect(config.contextLimit).toBe(128000);
      expect(config.enabled).toBe(true);
      expect(config.keepRecentTokens).toBe(2000);
      expect(config.maxTokens).toBe(8000);
      expect(config.reserveTokens).toBe(2000);
      expect(config.speculativeStartRatio).toBe(0.5);
      expect(config.thresholdRatio).toBe(0.5);
    });

    it("should verify optional field types", () => {
      const config: CompactionConfig = {
        contextLimit: 0, // 0 means unlimited
        enabled: false,
        keepRecentTokens: 0,
        maxTokens: 0,
        reserveTokens: 0,
        speculativeStartRatio: 0.15,
        thresholdRatio: 0,
      };
      expect(typeof config.contextLimit).toBe("number");
      expect(typeof config.enabled).toBe("boolean");
      expect(typeof config.keepRecentTokens).toBe("number");
      expect(typeof config.maxTokens).toBe("number");
      expect(typeof config.reserveTokens).toBe("number");
      expect(typeof config.speculativeStartRatio).toBe("number");
      expect(typeof config.thresholdRatio).toBe("number");
    });
  });

  // ============================================
  // 5. PruningConfig Interface
  // ============================================
  describe("PruningConfig", () => {
    it("should have all optional fields with default values from JSDoc", () => {
      const config: PruningConfig = {};
      // Default values from JSDoc comments:
      // eagerPruneToolNames: []
      // enabled: false
      // minSavingsTokens: 200
      // protectedToolNames: []
      // protectRecentTokens: 2000
      // replacementText: "[output pruned — too large]"
      expect(config.eagerPruneToolNames).toBeUndefined();
      expect(config.enabled).toBeUndefined();
      expect(config.minSavingsTokens).toBeUndefined();
      expect(config.protectedToolNames).toBeUndefined();
      expect(config.protectRecentTokens).toBeUndefined();
      expect(config.replacementText).toBeUndefined();
    });

    it("should allow setting eagerPruneToolNames", () => {
      const config: PruningConfig = {
        eagerPruneToolNames: ["tool1", "tool2"],
      };
      expect(config.eagerPruneToolNames).toEqual(["tool1", "tool2"]);
    });

    it("should allow setting enabled", () => {
      const config: PruningConfig = { enabled: true };
      expect(config.enabled).toBe(true);
    });

    it("should allow setting minSavingsTokens", () => {
      const config: PruningConfig = { minSavingsTokens: 200 };
      expect(config.minSavingsTokens).toBe(200);
    });

    it("should allow setting protectedToolNames", () => {
      const config: PruningConfig = {
        protectedToolNames: ["protected1", "protected2"],
      };
      expect(config.protectedToolNames).toEqual(["protected1", "protected2"]);
    });

    it("should allow setting protectRecentTokens", () => {
      const config: PruningConfig = { protectRecentTokens: 2000 };
      expect(config.protectRecentTokens).toBe(2000);
    });

    it("should allow setting replacementText", () => {
      const config: PruningConfig = {
        replacementText: "[output pruned — too large]",
      };
      expect(config.replacementText).toBe("[output pruned — too large]");
    });

