      expect(segment.messageCount).toBe(prepared.messageCount);
    });

    it("CompactionSummary should be compatible with null in summary field", () => {
      const segmentWithSummary: CompactionSegment = {
        createdAt: new Date(),
        endMessageId: "end",
        estimatedTokens: 100,
        id: "seg1",
        messageCount: 5,
        messageIds: ["m1"],
        messages: [],
        startMessageId: "start",
        summary: {
          createdAt: new Date(),
          firstKeptMessageId: "first",
          id: "sum1",
          summary: "test",
          summaryTokens: 50,
          tokensBefore: 500,
        },
      };
      const segmentWithoutSummary: CompactionSegment = {
        createdAt: new Date(),
        endMessageId: "end",
        estimatedTokens: 100,
        id: "seg2",
        messageCount: 5,
        messageIds: ["m1"],
        messages: [],
        startMessageId: "start",
        summary: null,
      };
      expect(segmentWithSummary.summary).not.toBeNull();
      expect(segmentWithoutSummary.summary).toBeNull();
    });
  });
});

